mapper.select:
SELECT r.*, u.real_name AS studentName, u.id_card AS studentIdCard, p.plan_name AS planName, p.plan_code AS planCode, c.course_name AS courseName, p.exam_date AS examDate, p.location AS examLocation, p.start_time AS startTime, p.end_time AS endTime FROM sys_registration r LEFT JOIN sys_user u ON u.id = r.student_id LEFT JOIN sys_exam_plan p ON p.id = r.plan_id LEFT JOIN sys_course c ON c.id = p.course_id WHERE r.deleted = 0 AND r.student_id = #{q.studentId} AND r.plan_id = #{q.planId} AND r.status = #{q.status} AND r.payment_status = #{q.paymentStatus}
AND (u.real_name LIKE '%' || #{q.keyword} || '%' OR p.plan_name LIKE '%' || #{q.keyword} || '%' OR r.registration_no LIKE '%' || #{q.keyword} || '%')
ORDER BY r.id DESC
